class MyStack {
public:
    MyStack() {

    }

    void push(int x) {
        q2.push(x);
        while (!q1.empty()) {
            q2.push(q1.front());
            q1.pop();
        }
        swap(q1, q2);
    }

    int pop() {
        if (empty()) {
            throw runtime_error("Stack is empty");
        }
        int top = q1.front();
        q1.pop();
        return top;
    }

    int top() {
        if (empty()) {
            throw runtime_error("Stack is empty");
        }
        return q1.front();
    }

    bool empty() {
        return q1.empty();
    }

private:
    queue<int> q1;
    queue<int> q2;
};
```
